display.text:
import { createHash, randomUUID } from "node:crypto";
import { realpath } from "node:fs/promises";
import { ProcessSupervisor } from "../workers/process-supervisor.js";
import type { ProjectConfig } from "../projects/project-config.js";
import { z } from "zod";

const DEFAULT_TIMEOUT_MS = 120_000;

export interface ValidationReport {
  readonly name: string;
  readonly outcome: "completed" | "cancelled" | "timed_out" | "failed";
  readonly exitCode: number | null;
  readonly stdout: string;
  readonly stderr: string;
  readonly startedAt: string;
  readonly finishedAt: string;
  readonly command: readonly string[];
  readonly argvSha256: string;
  readonly outputSha256: string;
  readonly provenance: DurableValidationProvenance;
}

export interface DurableValidationProvenance {
  readonly invocationId: string;
  readonly canonicalCwd: string;
  readonly subjectSha256: string | null;
}

export interface ValidationRunContext {
  readonly invocationId: string;
  readonly subjectSha256: string;
}

export interface ExpectedValidationProvenance extends ValidationRunContext {
  readonly canonicalCwd: string;
}

const ValidationProvenanceSchema = z.strictObject({
  invocationId: z.string().min(1),
  canonicalCwd: z.string().min(1),
  subjectSha256: z.string().min(1).nullable(),
});

export const ValidationReportSchema = z.strictObject({
  name: z.string().min(1),
  outcome: z.enum(["completed", "cancelled", "timed_out", "failed"]),
  exitCode: z.number().int().nullable(),
  stdout: z.string(),
  stderr: z.string(),
  startedAt: z.string().datetime({ offset: true }),
  finishedAt: z.string().datetime({ offset: true }),
  command: z.array(z.string()).min(1),
  argvSha256: z.string().regex(/^[a-f0-9]{64}$/),
  outputSha256: z.string().regex(/^[a-f0-9]{64}$/),
  provenance: ValidationProvenanceSchema,
}).superRefine((report, context) => {
  if (report.outcome === "completed" && report.exitCode !== 0) {
    context.addIssue({ code: "custom", message: "completed validation requires exitCode 0" });
  }
  if (report.outcome === "failed" && report.exitCode === 0) {
    context.addIssue({ code: "custom", message: "failed validation cannot have exitCode 0" });
  }
  if (
    (report.outcome === "cancelled" || report.outcome === "timed_out") &&
    report.exitCode !== null
  ) {
    context.addIssue({ code: "custom", message: `${report.outcome} validation requires null exitCode` });
  }
  if (Date.parse(report.finishedAt) < Date.parse(report.startedAt)) {
    context.addIssue({ code: "custom", message: "validation finishedAt precedes startedAt" });
  }
});

const verifiedValidationReports = new WeakMap<ValidationReport, DurableValidationProvenance>();
const usedInvocationIds = new Set<string>();

export function isVerifiedValidationReport(
  report: ValidationReport,
  expected?: ExpectedValidationProvenance,
): boolean {
  const provenance = verifiedValidationReports.get(report);
  if (provenance === undefined) return false;
  if (expected === undefined) return true;
  return (
    provenance.invocationId === expected.invocationId &&
    provenance.canonicalCwd === expected.canonicalCwd &&
    provenance.subjectSha256 === expected.subjectSha256
  );
}

export function isVerifiedValidationSubject(
  report: ValidationReport,
  subjectSha256: string,
): boolean {
  return verifiedValidationReports.get(report)?.subjectSha256 === subjectSha256;
}

export interface ValidationRunnerOptions {
  readonly timeoutMs?: number;
}

export class ValidationRunner {
  private readonly timeoutMs: number;

  constructor(
    private readonly supervisor: ProcessSupervisor,
    options: ValidationRunnerOptions = {}
  ) {
    this.timeoutMs = options.timeoutMs ?? DEFAULT_TIMEOUT_MS;
  }

  async run(
    project: ProjectConfig,
    name: "focused" | "full",
    cwd: string,
    signal: AbortSignal,
    context?: ValidationRunContext,
  ): Promise<ValidationReport> {
    const configuredCommand = project.validations[name];
    const command: readonly [string, ...string[]] = [
      configuredCommand[0],
      ...configuredCommand.slice(1),
    ];
    const invocationId = context?.invocationId ?? randomUUID();
    if (invocationId === "" || usedInvocationIds.has(invocationId)) {
      throw new Error("validation invocationId must be nonempty and single-use");
    }
    if (context !== undefined && context.subjectSha256 === "") {
      throw new Error("validation subjectSha256 must be nonempty");
    }
    usedInvocationIds.add(invocationId);
    const canonicalCwd = await realpath(cwd);
    const startedAt = new Date().toISOString();

    const result = await this.supervisor.execute(
      {
        taskId: "validation",
        executable: command[0],
        args: command.slice(1),
        cwd: canonicalCwd,
        timeoutMs: this.timeoutMs,
      },
      signal
    );

    const finishedAt = new Date().toISOString();

    const argvSha256 = createHash("sha256")
      .update(JSON.stringify(command), "utf8")
      .digest("hex");

    const stdout = result.rawStdout;
    const outputContent = JSON.stringify({ stdout, stderr: result.stderr });
    const outputSha256 = createHash("sha256")
      .update(outputContent, "utf8")
      .digest("hex");
    const provenance: DurableValidationProvenance = Object.freeze({
      invocationId,
      canonicalCwd,
      subjectSha256: context?.subjectSha256 ?? null,
    });

    const parsed = ValidationReportSchema.parse({
      name,
      outcome: result.outcome,
      exitCode: result.exitCode,
      stdout,
      stderr: result.stderr,
      startedAt,
      finishedAt,
      command,
      argvSha256,
      outputSha256,
      provenance,
    });
    const frozen: ValidationReport = Object.freeze({
      ...parsed,
      command: Object.freeze([...parsed.command]),
      provenance: Object.freeze({ ...parsed.provenance }),
    });
    verifiedValidationReports.set(frozen, frozen.provenance);
    return frozen;
  }
}

# Zentra Local Development Orchestrator MVP Implementation Plan

> **For agentic workers:** REQUIRED SUB-SKILL: Use superpowers:subagent-driven-development (recommended) or superpowers:executing-plans to implement this plan task-by-task.
> Steps use checkbox (`- [ ]`) syntax for tracking.

**Goal:** Build a local TypeScript orchestrator that durably executes one software-development ticket through worktree creation, deterministic worker execution, validation, independent review, integration, and evidence-backed completion.

**Architecture:** Zentra begins as one Node.js process with deep internal modules for contracts, event persistence, projections, project configuration, Git workspaces, supervised workers, validation, review, and integration.
The first tracer bullet uses a deterministic fixture worker rather than a real coding harness so the orchestration, authority, cancellation, recovery, and evidence contracts can be proven before provider-specific risk is introduced.

**Tech Stack:** Node.js 24, TypeScript 5.9, pnpm 10, Zod, better-sqlite3, Commander, Vitest, and native Git subprocesses invoked without a shell.

## Global Constraints

- Execute the implementation in this repository on an isolated feature worktree.
- Use Node.js 24 or newer and pnpm 10.
- Target macOS for the first process-supervision and Git integration implementation, with Linux and Windows conformance planned separately.
- Keep the kernel domain-neutral even though the first capability package is software development.
- Do not expose a general shell capability.
- Invoke subprocesses with executable and argument arrays and `shell: false`.
- Pass workers and validation commands an explicit minimal environment rather than inheriting the full parent environment.
- Keep the event journal as the source of truth and treat task views as rebuildable projections.
- Use only `completed`, `cancelled`, `denied`, `timed_out`, or `failed` as terminal task outcomes.
- Keep `blocked`, `awaiting_approval`, `interrupted`, and process exit as lifecycle states or causes.
- Distinguish immutable task and event history from disposable process and worktree state.
- Never retry a potentially effectful operation automatically after an uncertain result.
- Use one sentence per physical line in long Markdown documents.
- Do not add real OpenCode, Claude Code, Codex, remote execution, email, meeting, device, or distributed-worker integration in this MVP.

---

## Program Decomposition

The approved orchestrator design spans several independently deliverable subprojects.

This implementation plan covers only Subproject 1.

| Subproject | Outcome | Planned Separately |
| --- | --- | --- |
| 1. Local tracer bullet | One durable ticket reaches verified integration through deterministic local components | This plan |
| 2. Real harness containment | One supported coding harness runs in a reduced, cancellable development capsule | Yes |
| 3. Pod execution | Four agent roles coordinate one measurable outcome | Yes |
| 4. Multi-project operation | Project isolation, fair scheduling, and independent integration queues | Yes |
| 5. Twenty-agent scale | Backpressure, cost control, duplicate-work detection, and recovery | Yes |
| 6. Forty-agent scale | Failure-domain isolation, remote workers, and high-volume event processing | Yes |
| 7. Zoe workflow packages | Communication, meetings, personal operations, and devices | Yes |

---

